from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import os
from PIL import Image
import imghdr

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = '/path/to/upload/folder'
ALLOWED_EXTENSIONS = {'png', 'jpg', 'jpeg', 'gif'}
MAX_CONTENT_LENGTH = 2 * 1024 * 1024  # 2 MB

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = MAX_CONTENT_LENGTH

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def validate_image(file_path):
    try:
        with Image.open(file_path) as img:
            img.verify()
        return imghdr.what(file_path) in ALLOWED_EXTENSIONS
    except Exception:
        return False

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'}), 400

    file = request.files['file']

    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400

    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)

        if not validate_image(file_path):
            os.remove(file_path)
            return jsonify({'error': 'Invalid image content'}), 400

        # Generate a secure server-side filename
        server_filename = f"{os.urandom(16).hex()}.{filename.rsplit('.', 1)[1].lower()}"
        secure_path = os.path.join(app.config['UPLOAD_FOLDER'], server_filename)
        os.rename(file_path, secure_path)

        return jsonify({'message': 'File uploaded successfully', 'filename': server_filename}), 200

    return jsonify({'error': 'File type not allowed'}), 400

if __name__ == '__main__':
    app.run(debug=True)